const { ethers } = require('ethers');

const PRIVATE_KEY = 'your-private-key-here';
const RPC_URL = 'https://mainnet.infura.io/v3/your-infura-key';
const CONTRACT_ADDRESS = '0x742d35Cc6634C0532925a3b844Bc9e7595f0bEb';

const provider = new ethers.JsonRpcProvider(RPC_URL);
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

const ERC20_ABI = [
  'function transfer(address to, uint256 amount) returns (bool)',
  'function balanceOf(address account) view returns (uint256)',
  'function approve(address spender, uint256 amount) returns (bool)',
  'function allowance(address owner, address spender) view returns (uint256)',
  'function decimals() view returns (uint8)',
  'function symbol() view returns (string)',
  'function totalSupply() view returns (uint256)'
];

async function sendETH(toAddress, amountInEther) {
  try {
    const tx = {
      to: toAddress,
      value: ethers.parseEther(amountInEther.toString())
    };
    
    const transaction = await wallet.sendTransaction(tx);
    console.log('Transaction hash:', transaction.hash);
    
    const receipt = await transaction.wait();
    console.log('Transaction confirmed in block:', receipt.blockNumber);
    
    return receipt;
  } catch (error) {
    console.error('Error sending ETH:', error);
    throw error;
  }
}

async function getBalance(address) {
  try {
    const balance = await provider.getBalance(address);
    return ethers.formatEther(balance);
  } catch (error) {
    console.error('Error getting balance:', error);
    throw error;
  }
}

async function sendToken(contractAddress, toAddress, amount) {
  try {
    const contract = new ethers.Contract(contractAddress, ERC20_ABI, wallet);
    
    const decimals = await contract.decimals();
    const amountInWei = ethers.parseUnits(amount.toString(), decimals);
    
    const tx = await contract.transfer(toAddress, amountInWei);
    console.log('Token transfer hash:', tx.hash);
    
    const receipt = await tx.wait();
    console.log('Token transfer confirmed in block:', receipt.blockNumber);
    
    return receipt;
  } catch (error) {
    console.error('Error sending tokens:', error);
    throw error;
  }
}

async function getTokenBalance(contractAddress, accountAddress) {
  try {
    const contract = new ethers.Contract(contractAddress, ERC20_ABI, provider);
    const balance = await contract.balanceOf(accountAddress);
    const decimals = await contract.decimals();
    
    return ethers.formatUnits(balance, decimals);
  } catch (error) {
    console.error('Error getting token balance:', error);
    throw error;
  }
}

async function approveToken(contractAddress, spenderAddress, amount) {
  try {
    const contract = new ethers.Contract(contractAddress, ERC20_ABI, wallet);
    
    const decimals = await contract.decimals();
    const amountInWei = ethers.parseUnits(amount.toString(), decimals);
    
    const tx = await contract.approve(spenderAddress, amountInWei);
    console.log('Approval transaction hash:', tx.hash);
    
    const receipt = await tx.wait();
    console.log('Approval confirmed in block:', receipt.blockNumber);
    
    return receipt;
  } catch (error) {
    console.error('Error approving tokens:', error);
    throw error;
  }
}

async function callContractFunction(contractAddress, abi, functionName, params, value = '0') {
  try {
    const contract = new ethers.Contract(contractAddress, abi, wallet);
    
    const tx = await contract[functionName](...params, {
      value: ethers.parseEther(value.toString())
    });
    
    console.log('Contract call hash:', tx.hash);
    
    const receipt = await tx.wait();
    console.log('Contract call confirmed in block:', receipt.blockNumber);
    
    return receipt;
  } catch (error) {
    console.error('Error calling contract function:', error);
    throw error;
  }
}

async function readContractFunction(contractAddress, abi, functionName, params) {
  try {
    const contract = new ethers.Contract(contractAddress, abi, provider);
    const result = await contract[functionName](...params);
    return result;
  } catch (error) {
    console.error('Error reading contract function:', error);
    throw error;
  }
}

async function deployContract(abi, bytecode, constructorArgs = []) {
  try {
    const factory = new ethers.ContractFactory(abi, bytecode, wallet);
    const contract = await factory.deploy(...constructorArgs);
    
    console.log('Contract deployment hash:', contract.deploymentTransaction().hash);
    
    await contract.waitForDeployment();
    const address = await contract.getAddress();
    
    console.log('Contract deployed at:', address);
    
    return { contract, address };
  } catch (error) {
    console.error('Error deploying contract:', error);
    throw error;
  }
}

async function estimateGas(contractAddress, abi, functionName, params) {
  try {
    const contract = new ethers.Contract(contractAddress, abi, wallet);
    const gasEstimate = await contract[functionName].estimateGas(...params);
    return gasEstimate.toString();
  } catch (error) {
    console.error('Error estimating gas:', error);
    throw error;
  }
}

